// Extract search query and config from webhook
const input = $input.first().json.body || $input.first().json;
const query = input.query || input.q || '';
const maxResults = input.max_results || 5;
const collectionName = input.collection || 'Web Search';

if (!query) {
  throw new Error('Missing required field: query');
}

return [{ json: { query, maxResults, collectionName } }];

// Combine results from DuckDuckGo API and HTML search
const query = $('Parse Query').first().json.query;
const maxResults = $('Parse Query').first().json.maxResults;

// Try API results first
const apiData = $('DuckDuckGo Search').first().json;
let urls = [];

// API instant answer
if (apiData.AbstractURL) {
  urls.push({ url: apiData.AbstractURL, title: apiData.Heading || query, snippet: apiData.AbstractText || '' });
}

// Related topics from API
if (apiData.RelatedTopics) {
  for (const topic of apiData.RelatedTopics) {
    if (topic.FirstURL && urls.length < maxResults) {
      urls.push({ url: topic.FirstURL, title: topic.Text ? topic.Text.substring(0, 100) : '', snippet: topic.Text || '' });
    }
  }
}

// Parse HTML results as fallback/supplement
try {
  const html = $('DuckDuckGo HTML Search').first().json.data || '';
  const linkRegex = /class="result__a"[^>]*href="([^"]+)"[^>]*>([^<]+)/g;
  let match;
  while ((match = linkRegex.exec(html)) !== null && urls.length < maxResults) {
    let url = match[1];
    const title = match[2].trim();
    // DuckDuckGo wraps URLs in a redirect
    if (url.includes('uddg=')) {
      url = decodeURIComponent(url.split('uddg=')[1].split('&')[0]);
    }
    if (url.startsWith('http') && !urls.find(u => u.url === url)) {
      urls.push({ url, title, snippet: '' });
    }
  }
} catch (e) { /* ignore parse errors */ }

// If still no results, try a simple approach
if (urls.length === 0) {
  return [{ json: { error: 'No search results found for: ' + query, urls: [], query } }];
}

return [{ json: { query, urls: urls.slice(0, maxResults), resultCount: urls.length } }];

// Check if we have URLs to scrape
const data = $input.first().json;
if (data.error || !data.urls || data.urls.length === 0) {
  return [{ json: { skip: true, error: data.error || 'No URLs found' } }];
}

// Output each URL as a separate item for scraping
return data.urls.map(u => ({ json: { ...u, query: data.query } }));

// Convert scraped HTML to clean markdown text
const item = $input.first().json;
const url = $('Split URLs').first().json.url;
const title = $('Split URLs').first().json.title || url;
const query = $('Split URLs').first().json.query;

let html = item.data || item.body || '';
if (!html || typeof html !== 'string') {
  return [{ json: { skip: true, url, title, error: 'Empty page' } }];
}

// Strip scripts, styles, nav, footer, header
html = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '');
html = html.replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
html = html.replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '');
html = html.replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '');
html = html.replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '');

// Convert headings
html = html.replace(/<h1[^>]*>(.*?)<\/h1>/gi, '# $1\n\n');
html = html.replace(/<h2[^>]*>(.*?)<\/h2>/gi, '## $1\n\n');
html = html.replace(/<h3[^>]*>(.*?)<\/h3>/gi, '### $1\n\n');

// Convert formatting
html = html.replace(/<strong[^>]*>(.*?)<\/strong>/gi, '**$1**');
html = html.replace(/<b[^>]*>(.*?)<\/b>/gi, '**$1**');
html = html.replace(/<em[^>]*>(.*?)<\/em>/gi, '*$1*');
html = html.replace(/<i[^>]*>(.*?)<\/i>/gi, '*$1*');

// Convert links
html = html.replace(/<a[^>]*href="([^"]*?)"[^>]*>(.*?)<\/a>/gi, '[$2]($1)');

// Convert lists
html = html.replace(/<li[^>]*>(.*?)<\/li>/gi, '- $1\n');

// Convert paragraphs and breaks
html = html.replace(/<p[^>]*>(.*?)<\/p>/gi, '$1\n\n');
html = html.replace(/<br\s*\/?>/gi, '\n');

// Strip remaining HTML tags
html = html.replace(/<[^>]+>/g, '');

// Decode entities
html = html.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ');

// Clean up whitespace
html = html.replace(/\n{3,}/g, '\n\n').trim();

// Truncate to 50KB max per page
const maxLen = 50000;
let markdown = html.substring(0, maxLen);
if (html.length > maxLen) markdown += '\n\n[Content truncated]';

// Build the final document
const doc = '# ' + title + '\n\n' +
  '**Source:** ' + url + '\n' +
  '**Search Query:** ' + query + '\n' +
  '**Scraped:** ' + new Date().toISOString().split('T')[0] + '\n\n' +
  '---\n\n' + markdown;

return [{ json: { skip: false, url, title, query, content: doc, contentLength: doc.length } }];

// Find or create the 'Web Search' Knowledge Base collection
const OPENWEBUI_URL = 'CONFIGURE_OPENWEBUI_URL';
const API_KEY = 'CONFIGURE_API_KEY';
const collectionName = $('Parse Query').first().json.collectionName;

// List existing KBs
const listResp = await this.helpers.httpRequest({
  method: 'GET',
  url: OPENWEBUI_URL + '/api/v1/knowledge/',
  headers: { 'Authorization': 'Bearer ' + API_KEY },
  json: true
});

const items = listResp.items || (Array.isArray(listResp) ? listResp : []);
const existing = items.find(kb => kb.name === collectionName);

if (existing) {
  return [{ json: { kb_id: existing.id, kb_name: collectionName, created: false } }];
}

// Create new KB
const createResp = await this.helpers.httpRequest({
  method: 'POST',
  url: OPENWEBUI_URL + '/api/v1/knowledge/create',
  headers: { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' },
  body: { name: collectionName, description: 'Auto-scraped web search results for knowledge base' },
  json: true
});

return [{ json: { kb_id: createResp.id, kb_name: collectionName, created: true } }];

// Upload scraped content as a file to Open WebUI and add to KB
const OPENWEBUI_URL = 'CONFIGURE_OPENWEBUI_URL';
const API_KEY = 'CONFIGURE_API_KEY';
const kb_id = $('Find or Create KB').first().json.kb_id;

const content = $('HTML to Markdown').first().json.content;
const title = $('HTML to Markdown').first().json.title || 'search-result';
const query = $('HTML to Markdown').first().json.query;

// Create filename
const cleanTitle = title.replace(/[^a-zA-Z0-9 ]/g, '').substring(0, 40).trim();
const fileName = '[Search] ' + cleanTitle + '_' + Date.now() + '.md';

// Upload file
const FormData = require('form-data');
const form = new FormData();
form.append('file', Buffer.from(content, 'utf-8'), { filename: fileName, contentType: 'text/markdown' });

const uploadResp = await this.helpers.httpRequest({
  method: 'POST',
  url: OPENWEBUI_URL + '/api/v1/files/',
  headers: {
    'Authorization': 'Bearer ' + API_KEY,
    ...form.getHeaders()
  },
  body: form,
  json: true
});

if (!uploadResp.id) {
  return [{ json: { error: 'Upload failed', title } }];
}

// Add file to KB
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: OPENWEBUI_URL + '/api/v1/knowledge/' + kb_id + '/file/add',
    headers: { 'Authorization': 'Bearer ' + API_KEY, 'Content-Type': 'application/json' },
    body: { file_id: uploadResp.id },
    json: true
  });
} catch (e) {
  // Continue even if KB add fails
}

return [{ json: { success: true, file_id: uploadResp.id, fileName, title, kb_id } }];

// Collect all results and build summary
const query = $('Parse Query').first().json.query;
const allResults = $('Upload to KB').all();

const successful = allResults.filter(r => r.json.success);
const failed = allResults.filter(r => !r.json.success);

return [{ json: {
  query,
  total_scraped: successful.length,
  total_failed: failed.length,
  files: successful.map(r => ({ file_id: r.json.file_id, title: r.json.title, fileName: r.json.fileName })),
  kb_id: successful.length > 0 ? successful[0].json.kb_id : null,
  message: 'Scraped ' + successful.length + ' pages for "' + query + '" and added to Knowledge Base'
} }];
